import { Router } from "express";
import * as SupplierController from "../controllers/supplier.controller.js";
import { authenticateToken, authorizeRoles } from "../middlewares/auth.middleware.js";
import { validateRequest } from "../middlewares/validate.middleware.js";
import { createSupplierSchema, updateSupplierSchema } from "../schemas/supplier.schema.js";
const router = Router();
router.use(authenticateToken);
router.post("/", authorizeRoles("ADMIN", "STORE_ADMIN", "BRANCH_MANAGER"), validateRequest(createSupplierSchema), SupplierController.createSupplier);
router.get("/", SupplierController.getSuppliers);
router.patch("/:id", authorizeRoles("ADMIN", "STORE_ADMIN", "BRANCH_MANAGER"), validateRequest(updateSupplierSchema), SupplierController.updateSupplier);
router.delete("/:id", authorizeRoles("ADMIN", "STORE_ADMIN"), SupplierController.deleteSupplier);
export default router;
